mapper.select:
/* getPointHistory */ SELECT
FROM tb_mbm_user u INNER JOIN tb_mbm_point p ON u.id = p.user_id INNER JOIN tb_mbm_point_history h ON p.id = h.point_id
ORDER BY h.id ASC ORDER BY h.id DESC
LIMIT #{offset}, #{recordSize}

mapper.update:
		UPDATE tb_mbm_point_history 
		SET	
 			 dr_cr                  = #{drCr				}
			,dr_point_type          = #{drPointType			}
			,avail_amount           = #{availAmount			}
			,memo                   = #{memo				}
		WHERE id = #{id}

mapper.insert:
/* insert PointHistoryEntity */
INSERT 
INTO tb_mbm_point_history (
						  point_id, dr_cr, cr_point_type, dr_point_type
						, admin_gift_yn

						, amount
						, avail_amount	/* 첫 입력 amount와 같은 값 입력 이 컬럼만을 계산식에 사용 */
						, memo

						, create_date
						, create_id
)VALUES(	
		 #{pointId}
		,#{drCr}
		,#{crPointType}
		,#{drPointType}
		,#{adminGiftYn}

		,#{amount}
		,#{amount}
		,#{memo}

		,NOW()
		,#{createId}
);

/* PointHistoryDetailEntity */
INSERT 
INTO tb_mbm_point_history_detail (
						  history_id
						, dr_point_type

						, tot_amt
						, act_amt
						, rem_amt

						, npay_id
						, cash_id

						, create_date
						, create_id
)VALUES(	
		 #{historyId}
		,#{drPointType}

		,#{totAmt}
		,#{actAmt}
		,#{remAmt}

		,#{npayId}
		,#{cashId}

		,NOW()
		,#{createId}
);

mapper.select:
/* getPointHistoryDetail */ SELECT
FROM tb_mbm_user u INNER JOIN tb_mbm_point p ON u.id = p.user_id INNER JOIN tb_mbm_point_history h ON p.id = h.point_id LEFT JOIN tb_mbm_point_history_detail d ON h.id = d.history_id
ORDER BY h.id, d.id ASC

/* getPointHistoryNew */ SELECT h.id, p.user_id, h.point_id, h.dr_cr, GET_CODE_NAME('point_drcr', h.dr_cr) AS drCrName, h.cr_point_type, GET_CODE_NAME('point_type', h.cr_point_type) AS crPointTypeName,
h.amount AS display_amount, h.avail_amount,
NULL AS act_amt, NULL AS detailDrPointTypeName, NULL AS dr_point_type,
h.create_date, 1 AS sort_order FROM tb_mbm_point p INNER JOIN tb_mbm_point_history h ON p.id = h.point_id WHERE p.user_id = #{searchUserId}
UNION ALL
SELECT h.id, p.user_id, h.point_id, h.dr_cr, GET_CODE_NAME('point_drcr', h.dr_cr) AS drCrName, h.cr_point_type, GET_CODE_NAME('point_type', h.cr_point_type) AS crPointTypeName,
NULL AS display_amount, NULL AS avail_amount,
d.act_amt, GET_CODE_NAME('point_type', d.dr_point_type) AS detailDrPointTypeName, d.dr_point_type,
h.create_date, 2 AS sort_order FROM tb_mbm_point p INNER JOIN tb_mbm_point_history h ON p.id = h.point_id LEFT JOIN tb_mbm_point_history_detail d ON h.id = d.history_id WHERE IFNULL(act_amt, 0) != 0 AND p.user_id = #{searchUserId}
ORDER BY id DESC, create_date, sort_order
